<?php/***************************************************** * New user confirmation page.  Should only get here * * from an email link.                               * *****************************************************/require_once('../assets/db_inc_register_funcs.php');include_once('db_header_footer.php');site_header('Account Confirmation');if ($_GET['hash'] && $_GET['emailadres']) {  $worked = user_confirm();} else {  $feedback_str = "<P class=\"errormess\">ERROR - Bad link</P>";}if ($worked != 1) {  $noconfirm = '<P class="errormess">Something went wrong.  Send email to admin@example.com for help.  If you clicked through to this page directly, please go to login.php instead.</P>';} else {   $confirm = '<P class="big">You are now confirmed. <A HREF="login.php">Log in</A> to start browsing the site</P>';}$page = <<< EOPAGE<TABLE CELLPADDING=0 CELLSPACING=0 BORDER=0 ALIGN=CENTER WIDTH=621><TR>  <TD><IMG WIDTH=15 HEIGHT=1 SRC=../images/spacer.gif></TD>  <TD WIDTH=606 CLASS=left>  $feedback_str  $noconfirm  $confirm  </TD></TR></TABLE>EOPAGE;echo $page;site_footer();?>